import os
import re

# Look for more relaxed patterns:
# cmpwi
# beq
# blt
# b (to same label or similar structure)

for root, dirs, files in os.walk('build/GALE01/asm/melee/ft'):
    for fname in sorted(files):
        if not fname.endswith('.s'):
            continue
        fpath = os.path.join(root, fname)
        with open(fpath, 'r') as f:
            lines = f.readlines()

        # Look for cmpwi followed by beq, blt/ble, b in sequence
        for i in range(len(lines) - 4):
            if 'cmpwi' in lines[i] and ('0x0' in lines[i] or '0x00' in lines[i]):
                # Count next 3-4 actual instruction lines
                instrs = []
                j = i + 1
                while len(instrs) < 4 and j < len(lines):
                    if '*/' in lines[j] and '\t' in lines[j]:
                        instrs.append((j, lines[j]))
                    j += 1

                if len(instrs) >= 3:
                    if 'beq' in instrs[0][1] and ('blt' in instrs[1][1] or 'ble' in instrs[1][1]) and instrs[2][1].strip().endswith('b '):
                        # Extract labels
                        m1 = re.search(r'\.L[\dA-Fa-f_]+', instrs[1][1])
                        m2 = re.search(r'\.L[\dA-Fa-f_]+', instrs[2][1])
